// Supports two payload shapes:
// 1. Full VNTANA webhook: { product, organization, client }
// 2. Manual trigger:      { productUuid, clientUuid, orgUuid?, orgSlug?, clientSlug? }
const body = $input.first().json.body ?? $input.first().json;

let productUuid, clientUuid, orgUuid, orgSlug, clientSlug, assetBlobId, productName;

if (body.product) {
  // VNTANA webhook payload
  productUuid  = body.product.uuid;
  productName  = body.product.name;
  assetBlobId  = body.product.asset?.assetBlobId ?? '';
  orgUuid      = body.organization?.uuid ?? '49a01b09-ee65-4fc5-8777-433d7b5b5b29';
  orgSlug      = body.organization?.slug ?? 'DCicero';
  clientUuid   = body.client?.uuid ?? 'b577b1c8-80bd-4dab-b1b1-b22f9de4671a';
  clientSlug   = body.client?.slug ?? 'n8n-work';
} else {
  // Manual trigger
  productUuid  = body.productUuid;
  clientUuid   = body.clientUuid   ?? 'b577b1c8-80bd-4dab-b1b1-b22f9de4671a';
  orgUuid      = body.orgUuid      ?? '49a01b09-ee65-4fc5-8777-433d7b5b5b29';
  orgSlug      = body.orgSlug      ?? 'DCicero';
  clientSlug   = body.clientSlug   ?? 'n8n-work';
  productName  = body.productName  ?? '';
  assetBlobId  = body.assetBlobId  ?? '';
}

if (!productUuid) throw new Error('productUuid is required');

return [{ json: { productUuid, clientUuid, orgUuid, orgSlug, clientSlug, productName, assetBlobId } }];

// Use blob ID from webhook payload if present; fall back to product API response
const ids = $node['Extract IDs'].json;
const product = $input.first().json.response;

const productName = product?.name ?? ids.productName ?? ids.productUuid;
const assetBlobId = ids.assetBlobId || product?.asset?.assetBlobId || '';

if (!assetBlobId) throw new Error(`No assetBlobId found for product ${ids.productUuid}`);

return [{ json: {
  ...ids,
  productName,
  assetBlobId
} }];

// Look for a prior scene mapping attachment (JSON file)
const attachments = $input.first().json.response?.grid ?? [];
const mapping = attachments
  .filter(a => (a.name ?? '').startsWith('scene-mapping-') && (a.name ?? '').endsWith('.json'))
  .sort((a, b) => new Date(b.created ?? 0) - new Date(a.created ?? 0))[0];

return [{ json: {
  hasPriorMapping: !!mapping,
  mappingBlobId:   mapping?.blobId  ?? null,
  mappingName:     mapping?.name    ?? null
} }];

// Parse the GLB binary's JSON chunk and extract the scene node hierarchy.
// GLB format: 12-byte header, then chunks. First chunk is JSON (type 0x4E4F534A).
const binaryData = $input.first().binary?.glbData;
if (!binaryData) throw new Error('No GLB binary data in glbData field');

// n8n provides binary as Buffer-like; access via Buffer.from
const buf = Buffer.from(binaryData.data, 'base64');

// Validate GLB magic: 0x46546C67
const magic = buf.readUInt32LE(0);
if (magic !== 0x46546C67) throw new Error(`Not a valid GLB file (magic: 0x${magic.toString(16)})`);

// Read JSON chunk: bytes 12-19 are chunk header (length + type)
const jsonChunkLength = buf.readUInt32LE(12);
const jsonChunkType   = buf.readUInt32LE(16);
if (jsonChunkType !== 0x4E4F534A) throw new Error('First GLB chunk is not JSON');

const jsonStr = buf.slice(20, 20 + jsonChunkLength).toString('utf8').replace(/\0+$/, '');
const gltf = JSON.parse(jsonStr);

const nodes = gltf.nodes ?? [];
const meshes = gltf.meshes ?? [];

// Build child -> parent index map
const parentOf = new Array(nodes.length).fill(-1);
nodes.forEach((node, i) => {
  (node.children ?? []).forEach(ci => { parentOf[ci] = i; });
});

// For a given node index, walk up to find the nearest named ancestor (not NONE / not empty)
function findNamedAncestor(idx) {
  let cur = parentOf[idx];
  while (cur !== -1) {
    const name = (nodes[cur]?.name ?? '').trim();
    if (name && name.toUpperCase() !== 'NONE') return name;
    cur = parentOf[cur];
  }
  return null;
}

// Extract flat list of mesh nodes with suggested names
const meshNodes = [];
nodes.forEach((node, i) => {
  if (node.mesh === undefined) return;
  const rawName      = (node.name ?? '').trim();
  const meshName     = gltf.meshes[node.mesh]?.name ?? '';
  const namedAncestor = findNamedAncestor(i);
  const isNone       = !rawName || rawName.toUpperCase() === 'NONE';

  meshNodes.push({
    nodeIndex:     i,
    meshIndex:     node.mesh,
    rawName:       rawName || 'NONE',
    meshName:      meshName || '',
    suggestedName: isNone ? (namedAncestor ?? '') : rawName,
    namedAncestor: namedAncestor ?? '',
    needsRename:   isNone
  });
});

// Full tree for reference (recursive helper)
function buildTree(idx) {
  const n = nodes[idx];
  return {
    index: idx,
    name: (n.name ?? 'NONE'),
    hasMesh: n.mesh !== undefined,
    meshIndex: n.mesh ?? null,
    children: (n.children ?? []).map(buildTree)
  };
}
const roots = nodes
  .map((_, i) => i)
  .filter(i => parentOf[i] === -1)
  .map(buildTree);

const ids = $node['Extract IDs'].json;
return [{ json: {
  productUuid:  ids.productUuid,
  productName:  $node['Resolve Blob ID'].json.productName,
  clientUuid:   ids.clientUuid,
  assetBlobId:  ids.assetBlobId,
  totalNodes:   nodes.length,
  totalMeshes:  meshNodes.length,
  needsRename:  meshNodes.filter(m => m.needsRename).length,
  meshNodes,
  sceneRoots:   roots
} }];

// Merge with prior mapping if one exists; mark new nodes
const tree     = $node['Parse Scene Tree'].json;
const prior    = $node['Find Existing Mapping'].json;

const mapping = {
  productUuid:   tree.productUuid,
  productName:   tree.productName,
  assetBlobId:   tree.assetBlobId,
  extractedAt:   new Date().toISOString(),
  hasPriorMapping: prior.hasPriorMapping,
  totalNodes:    tree.totalNodes,
  totalMeshes:   tree.totalMeshes,
  needsRename:   tree.needsRename,
  // Each entry: { nodeIndex, rawName, suggestedName, confirmedName, isNew, needsRename }
  entries: tree.meshNodes.map(m => ({
    nodeIndex:     m.nodeIndex,
    meshIndex:     m.meshIndex,
    rawName:       m.rawName,
    meshName:      m.meshName,
    suggestedName: m.suggestedName,
    confirmedName: m.suggestedName,  // default; user edits in mapper UI
    namedAncestor: m.namedAncestor,
    needsRename:   m.needsRename,
    isNew:         false  // will be set to true if no prior mapping had this nodeIndex
  }))
};

// Mark new nodes relative to prior mapping
if (prior.hasPriorMapping && prior.priorEntries) {
  const priorIndexes = new Set((prior.priorEntries ?? []).map(e => e.nodeIndex));
  mapping.entries.forEach(e => { e.isNew = !priorIndexes.has(e.nodeIndex); });
}

const jsonStr = JSON.stringify(mapping, null, 2);
const fileName = `scene-mapping-${tree.productUuid}.json`;

return [{ json: { mapping, jsonStr, fileName, productUuid: tree.productUuid, clientUuid: tree.clientUuid, productName: tree.productName } }];

// Convert the JSON string to binary so it can be uploaded as a file
const item = $input.first();
const jsonStr = item.json.jsonStr;
const fileName = item.json.fileName;

const binary = {
  mappingFile: await this.helpers.prepareBinaryData(
    Buffer.from(jsonStr, 'utf8'),
    fileName,
    'application/json'
  )
};

return [{ json: item.json, binary }];

const m = $node['Build Mapping JSON'].json;
const mapperUrl = `https://vntana-store-production.up.railway.app/admin/parts-mapper.html?uuid=${m.productUuid}&clientUuid=${m.clientUuid}`;

const lines = [
  `*Parts Mapper ready: ${m.productName}*`,
  `${m.mapping.needsRename} of ${m.mapping.totalMeshes} mesh nodes need renaming.`,
  m.hasPriorMapping ? 'Prior mapping found — new geometry will be flagged.' : 'First-time extract.',
  '',
  `<${mapperUrl}|Open Parts Mapper>`
];

return [{ json: { mapperUrl, slackText: lines.join('\n'), ...m } }];
